    studies: [{"title": "How common is vitamin B-12 deficiency?", "authors": "Allen LH", "year": 2009, "journal": "Am J Clin Nutr", "design": "Revue", "n": null, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=How%20common%20is%20vitamin%20B-12%20deficiency%3F", "finding": "La carence en vitamine B12 touche 10 à 30 % des personnes âgées dans le monde ; les taux sont plus élevés dans les populations végétaliennes/végétariennes et chez celles souffrant de gastrite atrophique. Carence subclinique beaucoup plus fréquente que l’anémie manifeste.", "limitations": "Article de révision. Les définitions de la carence varient selon les études."}, {"title": "Effects of homocysteine-lowering with folic acid plus vitamin B12 vs placebo on stroke and other vascular events in patients with stroke or transient ischemic attack", "authors": "VITATOPS Trial Study Group", "year": 2010, "journal": "Lancet Neurol", "design": "ECR (3,4 ans)", "n": 8164, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effects%20of%20homocysteine-lowering%20with%20folic%20acid%20plus%20vitamin%20B12%20vs%20placebo%20on%20stroke%20and%20other%20vascular%20events%20in%20patients%20with%20stroke%20or%20transient%20ischemic%20attack", "finding": "Folate + B12 + B6 ont réduit l'homocystéine mais n'ont pas réduit la récidive d'accident vasculaire cérébral ou les événements vasculaires composites par rapport au placebo sur 3,4 ans.", "limitations": "Résultat négatif : test direct pour savoir si la supplémentation en vitamine B prévient les événements dans une population non déficiente. Je ne l'ai pas fait."}],
