    studies: [{"title": "Mucolytic agents versus placebo for chronic bronchitis or chronic obstructive pulmonary disease", "authors": "Cazzola M, Calzetta L, Page C, Jardim J, Chuchalin AG, Rogliani P, Matera MG", "year": 2015, "journal": "Cochrane Database Syst Rev", "design": "Méta-analyse (≥30 ECR)", "n": 13000, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Mucolytic%20agents%20versus%20placebo%20for%20chronic%20bronchitis%20or%20chronic%20obstructive%20pulmonary%20disease", "finding": "Les mucolytiques (principalement la NAC à 1 200 mg/jour) ont réduit les exacerbations et légèrement amélioré la qualité de vie dans la bronchite chronique/MPOC par rapport au placebo. NNT ~ 8 pour éviter une exacerbation par an.", "limitations": "Formulations hétérogènes. Tous les sujets n’avaient pas une BPCO confirmée par spirométrie."}, {"title": "Effect of N-acetylcysteine in COPD exacerbations (PANTHEON): a randomised, double-blind placebo-controlled trial", "authors": "Zheng JP, Wen FQ, Bai CX, Wan HY, Kang J, Chen P, Yao WZ, Ma LJ, Li X, Raiteri L, Sardina M, Gao Y, Wang BS, Zhong NS", "year": 2014, "journal": "Lancet Respir Med", "design": "ECR (1 an)", "n": 1006, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Effect%20of%20N-acetylcysteine%20in%20COPD%20exacerbations%20%28PANTHEON%29%3A%20a%20randomised%2C%20double-blind%20placebo-controlled%20trial", "finding": "La NAC 600 mg deux fois par jour a réduit le taux d'exacerbation de 22 % par rapport au placebo sur 1 an dans la BPCO modérée à sévère. Le bénéfice est plus important chez les patients présentant des exacerbations antérieures fréquentes.", "limitations": "Essai dans un seul pays (Chine). N'a pas montré d'amélioration forcée du volume expiratoire."}],
