    studies: [{"title": "Blueberries improve biomarkers of cardiometabolic function in participants with metabolic syndrome", "authors": "Curtis PJ, van der Velpen V, Berends L, Jennings A, Feelisch M, Umpleby AM, Evans M, Fernandez BO, Meiss MS, Minnion M, Potter J, Minihane AM, Kay CD, Rimm EB, Cassidy A", "year": 2019, "journal": "Am J Clin Nutr", "design": "ECR (6 mois)", "n": 115, "url": "https://pubmed.ncbi.nlm.nih.gov/31136659/", "finding": "1 tasse/jour de myrtilles (équivalent 150 g lyophilisés) pendant 6 mois a amélioré la dilatation médiée par le flux (+1,45 points de pourcentage) et la TA systolique ambulatoire sur 24 heures d'environ 5 mmHg par rapport au placebo chez les sujets atteints du syndrome métabolique.", "limitations": "Les sujets présentaient un syndrome métabolique — l'effet peut être moindre chez les sujets sains. Financé par l’industrie (US Highbush Blueberry Council)."}, {"title": "High anthocyanin intake is associated with a reduced risk of myocardial infarction in young and middle-aged women", "authors": "Cassidy A, Mukamal KJ, Liu L, Franz M, Eliassen AH, Rimm EB", "year": 2013, "journal": "Circulation", "design": "Cohorte prospective (NHS II)", "n": 93600, "url": "https://pubmed.ncbi.nlm.nih.gov/23319811/", "finding": "Le quintile le plus élevé d'apport en anthocyanes (≥3 portions de baies/semaine) présentait un risque d'IM inférieur de 32 % par rapport au quintile le plus bas chez les femmes jeunes/d'âge moyen, après ajustement.", "limitations": "Observationnel. Biais d’utilisateur sain possible. Cohorte exclusivement féminine."}],
