    studies: [{"title": "Associations of regular glucosamine use with all-cause and cause-specific mortality: UK Biobank", "authors": "Li ZH, Zhang YJ, Wang ZH, Lv YB, Mao C, Yin ZX, Shi XM", "year": 2020, "journal": "Ann Rheum Dis", "design": "Cohorte prospective", "n": 495077, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Associations%20of%20regular%20glucosamine%20use%20with%20all-cause%20and%20cause-specific%20mortality%3A%20UK%20Biobank", "finding": "La consommation quotidienne de glucosamine était associée à un HR de 0,85 pour la mortalité toutes causes, de 0,78 pour la mortalité par maladies cardiovasculaires et de 0,94 pour la mortalité par cancer, après ajustement pour environ 30 facteurs de confusion.", "limitations": "Observationnel. Biais d’utilisateur sain possible. Utilisation de suppléments autodéclarée. Aucune donnée sur la dose ou la formulation."}, {"title": "Use of glucosamine and chondroitin in relation to mortality (VITAL cohort)", "authors": "Bell GA, Kantor ED, Lampe JW, Shen DD, White E", "year": 2012, "journal": "Eur J Epidemiol", "design": "Cohorte prospective", "n": 77719, "url": "https://pubmed.ncbi.nlm.nih.gov/?term=Use%20of%20glucosamine%20and%20chondroitin%20in%20relation%20to%20mortality%20%28VITAL%20cohort%29", "finding": "L'utilisation de glucosamine est associée à une mortalité toutes causes inférieure de 17 % et à une mortalité due aux maladies respiratoires inférieure de 41 %. Effet plus fort à une fréquence d’utilisation autodéclarée plus élevée.", "limitations": "Observationnel. Autodéclaré. Aucune donnée de formulation."}],
