    studies: [{"title": "Rapamycin fed late in life extends lifespan in genetically heterogeneous mice (ITP)", "authors": "Harrison, Strong, Sharp, Nelson, Astle, Flurkey et al.", "year": 2009, "journal": "Nature", "design": "ECR (souris)", "n": 1900, "url": "https://www.nature.com/articles/nature08221", "finding": "La rapamycine en fin de vie a prolongé la durée de vie médiane de 9 % (hommes) et de 14 % (femmes). La première démonstration de l'extension pharmacologique de la durée de vie a commencé après l'âge moyen chez les mammifères.", "limitations": "Modèle de souris. La traduction de la dose aux humains n’est pas triviale."}, {"title": "mTOR inhibition improves immune function in the elderly", "authors": "Mannick et al.", "year": 2014, "journal": "Science Translational Medicine", "design": "ECR (humains)", "n": 218, "url": "https://www.science.org/doi/10.1126/scitranslmed.3009892", "finding": "Une faible dose de RAD001 (évérolimus) pendant 6 semaines a amélioré la réponse vaccinale contre la grippe d'environ 20 % chez les personnes âgées. Le premier ECR humain montrant que l’inhibition de mTOR a un effet anti-âge fonctionnel.", "limitations": "Critère de substitution (réponse vaccinale), et non durée de vie."}, {"title": "PEARL: Participatory Evaluation of Aging with Rapamycin for Longevity", "authors": "Kaeberlein lab / AgelessRx", "year": 2024, "journal": "Aging (Albany NY)", "design": "ECR (humains)", "n": 114, "url": "https://www.aging-us.com/article/206135", "finding": "5 à 10 mg de rapamycine par semaine pendant 48 semaines : masse maigre bien tolérée préservée chez la femme. Aucun critère de mortalité.", "limitations": "Points de terminaison de substitution ; petit N; population sélectionnée."}],
